import { useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';

import BaseTamplateRequest from '../../consts/BaseTemplateRequest';
import { updateRow } from '../../consts/crud';
import '../../App.css';
import '../../../node_modules/bootstrap/dist/css/bootstrap.css'


function EditLocalityCrossroad() {
    const [loading, setLoading] = useState(false);
    const [localities, setLocalities] = useState('');
    // const [crossroads, setCrossroads] = useState('');
    // const [crossroads_roads_sings, setCrossroadsRoadsSings] = useState('');

    const [locality_id, setLocalityID] = useState('');
    const [road_sing_crossroad_id, setCrossroadRoadSingID] = useState('');

    const navigate = useNavigate();

    const { id } = useParams();

    const handleChangeLocalityID = (event) => { setLocalityID(event.target.value); };
    // const handleChangeCrossroadID = (event) => { setCrossroadID(event.target.value); };
    // const handleChangeCrossroadRoadsSingsID = (event) => { setCrossroadRoadsSingsID(event.target.value); };

    const submitLocalityCrossroad = async (e) => {
        e.preventDefault();
        const headers = {
            'Content-Type': 'multipart/form-data',
            'Accept': 'application/json'
        };
        const crossroad_road_sing = { road_sing_crossroad_id, locality_id };
        await updateRow('/localities/crossroads/roads/sings', id, crossroad_road_sing, headers);
        setCrossroadRoadSingID('');
        setLocalityID('');
        navigate('/localities/crossroads/roads/sings');
    };

    const fetchTableData = useCallback(async () => {
        setLoading(true);

        // const read_roads = await readRows('/roads');
        // setRoads(read_roads);

        const read_localities = await readRows('/localities');
        setLocalities(read_localities);

        setLoading(false);
    }, []);

    useEffect(() => {
        fetchTableData();
    }, [fetchTableData]);

    return (
        <div>
            { loading ? 
                (
                    <div>
                        <p>Загрузка данных...</p>
                    </div>
                ) : localStorage.getItem('login') !== '' ? 
                (
                    <div>
                        <BaseTamplateRequest />
                        <form className='container' onSubmit={submitLocalityCrossroad}>
                            <h1>Обновление знака на населенном пункте</h1>
                            <div className='mb-3'>
                                <lable className='form-label'>Название перекрестка</lable>
                                <input 
                                    type='text'
                                    name='road_sing_crossroad_id' 
                                    value={road_sing_crossroad_id.road_sing_crossroad_id} 
                                    onChange={(e) => setCrossroadRoadSingID(e.target.value)}
                                    className='form-input'  
                                    placeholder='road_sing_crossroad_id'
                                    required  
                                />
                            </div>
                            <div className='mb-3'>
                                <lable className='form-label'>Населенный пункт</lable>
                                <select 
                                        value={locality_id}
                                        onChange={handleChangeLocalityID}
                                        class="form-select"
                                        aria-label="Default select example"
                                    >
                                        <option value="">Населенный пункт</option>
                                        { localities?.items?.map(locality => (
                                            <option key={ locality.id } value={ locality.id }>
                                                { locality.name_locality }
                                            </option>
                                        ))}
                                </select>
                            </div>
                            <button 
                                type='submit' 
                                className='btn btn-primary'
                            >
                                Обновить
                            </button>
                            <button 
                                type='submit' 
                                className='btn btn-danger' 
                                onClick={() => navigate('/localities/crossroads/roads/sings')}
                            >
                                Назад
                            </button>
                        </form>
                    </div>
                ) : (
                    <p className='no-data'>Нет данных для отображения</p> 
                )
            }
        </div>
    )
};

export default EditLocalityCrossroad;
